import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useGame } from '../context/GameContext';
import Flag from '../components/Flag';

const CONTINENTS = [
    { name: 'Europe', icon: '🏰', color: 'from-blue-500/20 to-blue-900/40 border-blue-500/30' },
    { name: 'South America', icon: '🌎', color: 'from-green-500/20 to-green-900/40 border-green-500/30' },
    { name: 'Africa', icon: '🌍', color: 'from-orange-500/20 to-orange-900/40 border-orange-500/30' },
    { name: 'Asia', icon: '🏯', color: 'from-red-500/20 to-red-900/40 border-red-500/30' },
    { name: 'North America', icon: '🗽', color: 'from-indigo-500/20 to-indigo-900/40 border-indigo-500/30' },
    { name: 'Oceania', icon: '🏝️', color: 'from-cyan-500/20 to-cyan-900/40 border-cyan-500/30' },
];

export default function Onboarding() {
    const { state, dispatch } = useGame();
    const [step, setStep] = useState(0);
    const [selectedTeamIdx, setSelectedTeamIdx] = useState(-1);
    const [selectedContinent, setSelectedContinent] = useState(null);
    const [username, setUsername] = useState('');

    const filteredTeams = selectedContinent
        ? state.teams.filter(t => t.continent === selectedContinent)
        : [];

    const selectedTeam = selectedTeamIdx >= 0 ? state.teams[selectedTeamIdx] : null;

    const handleFinish = () => {
        dispatch({ type: 'SET_USERNAME', payload: username || 'Manager' });
        dispatch({ type: 'SELECT_TEAM', payload: selectedTeamIdx });
        dispatch({ type: 'AUTO_LINEUP' });
        dispatch({ type: 'START_GAME' });
    };

    const getTeamStars = (index) => {
        if (index < 5) return '★★★★★';
        if (index < 15) return '★★★★☆';
        if (index < 30) return '★★★☆☆';
        return '★★☆☆☆';
    };

    return (
        <div className="min-h-screen bg-spaceBlack text-white flex flex-col items-center justify-center relative overflow-hidden">
            <div className="absolute inset-0 z-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-neonBlue/10 via-spaceBlack to-spaceBlack"></div>
            <div className="absolute inset-0 z-0 bg-[linear-gradient(rgba(255,255,255,0.015)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.015)_1px,transparent_1px)] bg-[size:60px_60px]"></div>

            {/* Progress Bar */}
            <div className="relative z-10 w-full max-w-2xl px-8 mb-12">
                <div className="flex justify-between text-xs text-gray-500 mb-2 font-bold tracking-widest uppercase">
                    <span className={step >= 0 ? 'text-neonGold' : ''}>Continent</span>
                    <span className={step >= 1 ? 'text-neonGold' : ''}>Nation</span>
                    <span className={step >= 2 ? 'text-neonGold' : ''}>Identity</span>
                    <span className={step >= 3 ? 'text-neonGold' : ''}>Confirm</span>
                </div>
                <div className="h-1 bg-white/10 rounded-full overflow-hidden">
                    <motion.div className="h-full bg-neonGold" animate={{ width: `${((step + 1) / 4) * 100}%` }} />
                </div>
            </div>

            <AnimatePresence mode="wait">
                {/* STEP 0: Choose Continent */}
                {step === 0 && (
                    <motion.div key="s0" initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -30 }} className="relative z-10 text-center max-w-4xl px-8">
                        <h1 className="text-4xl md:text-5xl font-heading font-black text-neonGold mb-3">CHOOSE YOUR CONTINENT</h1>
                        <p className="text-gray-400 mb-10">Where does your footballing journey begin?</p>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-6 mb-10">
                            {CONTINENTS.map(c => (
                                <motion.div
                                    key={c.name}
                                    whileHover={{ scale: 1.05 }}
                                    whileTap={{ scale: 0.95 }}
                                    onClick={() => { setSelectedContinent(c.name); setStep(1); setSelectedTeamIdx(-1); }}
                                    className={`cursor-pointer rounded-2xl p-8 border bg-gradient-to-br ${c.color} flex flex-col items-center gap-3 hover:shadow-xl transition-shadow`}
                                >
                                    <span className="text-5xl">{c.icon}</span>
                                    <span className="font-bold text-lg">{c.name}</span>
                                    <span className="text-xs text-gray-400">{state.teams.filter(t => t.continent === c.name).length} Nations</span>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                )}

                {/* STEP 1: Pick Nation */}
                {step === 1 && (
                    <motion.div key="s1" initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -30 }} className="relative z-10 text-center max-w-3xl w-full px-8">
                        <button onClick={() => setStep(0)} className="text-gray-400 hover:text-white text-sm mb-6 flex items-center gap-2 mx-auto">← Back to Continents</button>
                        <h1 className="text-4xl font-heading font-black text-neonGold mb-3">SELECT YOUR NATION</h1>
                        <p className="text-gray-400 mb-10">{selectedContinent} — {filteredTeams.length} nations available</p>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-10 max-h-[400px] overflow-y-auto hide-scrollbar pr-2">
                            {filteredTeams.map(t => (
                                <motion.div
                                    key={t.id}
                                    whileHover={{ scale: 1.02 }}
                                    onClick={() => setSelectedTeamIdx(t.id)}
                                    className={`cursor-pointer rounded-xl p-5 flex items-center gap-5 border transition-all ${selectedTeamIdx === t.id ? 'border-neonGold bg-neonGold/10 shadow-[0_0_20px_rgba(255,215,0,0.15)]' : 'border-white/10 bg-white/5 hover:bg-white/10'}`}
                                >
                                    <Flag code={t.code} size="w-14 h-14" />
                                    <div className="text-left flex-1">
                                        <div className="font-bold text-lg">{t.name}</div>
                                        <div className="text-neonGold text-sm">{getTeamStars(t.id)}</div>
                                    </div>
                                    <div className="text-gray-500 font-bold text-sm">{t.abbr}</div>
                                </motion.div>
                            ))}
                        </div>
                        <button
                            disabled={selectedTeamIdx === -1}
                            onClick={() => setStep(2)}
                            className={`px-12 py-4 rounded-full font-bold text-lg transition-all ${selectedTeamIdx !== -1 ? 'bg-neonGreen text-black hover:scale-105' : 'bg-gray-800 text-gray-500 cursor-not-allowed'}`}
                        >NEXT →</button>
                    </motion.div>
                )}

                {/* STEP 2: Username */}
                {step === 2 && (
                    <motion.div key="s2" initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -30 }} className="relative z-10 text-center max-w-lg w-full px-8">
                        <button onClick={() => setStep(1)} className="text-gray-400 hover:text-white text-sm mb-6 flex items-center gap-2 mx-auto">← Back</button>
                        <h1 className="text-4xl font-heading font-black text-neonGold mb-3">MANAGER IDENTITY</h1>
                        <p className="text-gray-400 mb-10">Choose a name for the global leaderboard.</p>
                        <div className="bg-white/5 border border-white/10 rounded-2xl p-8 mb-10">
                            <input
                                type="text"
                                placeholder="Enter your manager name..."
                                value={username}
                                onChange={e => setUsername(e.target.value)}
                                maxLength={20}
                                className="w-full bg-black/60 border border-white/20 rounded-xl px-6 py-4 text-xl text-white font-bold outline-none focus:border-neonGold transition-colors text-center placeholder-gray-600"
                            />
                            <div className="text-xs text-gray-500 mt-3">{username.length}/20 characters</div>
                        </div>
                        <button
                            onClick={() => setStep(3)}
                            className="px-12 py-4 rounded-full font-bold text-lg bg-neonGreen text-black hover:scale-105 transition-all"
                        >NEXT →</button>
                    </motion.div>
                )}

                {/* STEP 3: Confirm Squad */}
                {step === 3 && selectedTeam && (
                    <motion.div key="s3" initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -30 }} className="relative z-10 text-center max-w-2xl w-full px-8">
                        <button onClick={() => setStep(2)} className="text-gray-400 hover:text-white text-sm mb-6 flex items-center gap-2 mx-auto">← Back</button>
                        <h1 className="text-4xl font-heading font-black text-neonGold mb-3">CONFIRM YOUR SQUAD</h1>
                        <p className="text-gray-400 mb-8">Your best XI has been auto-selected.</p>

                        <div className="bg-white/5 border border-white/10 rounded-2xl p-8 mb-8">
                            <div className="flex items-center justify-center gap-6 mb-6">
                                <Flag code={selectedTeam.code} size="w-20 h-20" />
                                <div className="text-left">
                                    <div className="text-3xl font-black">{selectedTeam.name}</div>
                                    <div className="text-gray-400">Manager: <span className="text-neonGold font-bold">{username || 'Manager'}</span></div>
                                </div>
                            </div>
                            <div className="grid grid-cols-4 gap-3">
                                {['GK', 'DEF', 'MID', 'FWD'].map(pos => {
                                    const players = selectedTeam.players.filter(p => p.position === pos).sort((a, b) => b.strength - a.strength);
                                    const count = pos === 'GK' ? 1 : pos === 'DEF' ? 4 : pos === 'MID' ? 4 : 2;
                                    return (
                                        <div key={pos}>
                                            <div className="text-xs text-neonGold font-bold mb-2">{pos}</div>
                                            {players.slice(0, count).map(p => (
                                                <div key={p.id} className="bg-black/40 rounded-lg p-2 mb-1 text-xs">
                                                    <div className="font-bold truncate">{p.name}</div>
                                                    <div className="text-neonGreen font-black">{p.strength}</div>
                                                </div>
                                            ))}
                                        </div>
                                    );
                                })}
                            </div>
                        </div>

                        <motion.button
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                            onClick={handleFinish}
                            className="px-16 py-5 rounded-full font-black text-xl bg-neonGold text-black shadow-[0_0_30px_rgba(255,215,0,0.3)] hover:shadow-[0_0_50px_rgba(255,215,0,0.5)] transition-shadow"
                        >
                            BEGIN YOUR CAREER →
                        </motion.button>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}
