
export default function Flag({ code, size = 'w-8 h-8', className = '' }) {
    if (!code) return <span className={`${size} flex items-center justify-center bg-white/5 rounded-full text-xl ${className}`}>🌍</span>;
    
    return (
        <img 
            src={`https://flagcdn.com/w40/${code}.png`} 
            srcSet={`https://flagcdn.com/w80/${code}.png 2x`}
            alt={`${code} flag`} 
            className={`inline-block object-cover rounded-full shadow-md ${size} ${className}`}
        />
    );
}
